"""노드/포트/엣지 모델."""

from __future__ import annotations

from dataclasses import dataclass, field
from typing import Any


@dataclass
class PortInfo:
    id: str
    type: str = "STR"
    multi: bool = False
    required: bool = True
    dependency: str | None = None
    dependency_value: Any | None = None


@dataclass
class EdgeInfo:
    source_node: str
    source_port: str
    target_node: str
    target_port: str


@dataclass
class NodeInfo:
    id: str
    function_id: str = "default"
    category_id: str = ""
    name: str = ""
    parameters: dict[str, Any] = field(default_factory=dict)
    inputs: list[PortInfo] = field(default_factory=list)
    outputs: list[PortInfo] = field(default_factory=list)
    bypass: bool = False
    position: tuple[float, float] = (0.0, 0.0)
    node_class: Any | None = None  # execute() 호출용
